import { quote, claim, type Item, type QuoteResult } from "./claim-office.js";

let input = "";
process.stdin.setEncoding("utf8");
process.stdin.on("data", (chunk) => {
  input += chunk;
});
process.stdin.on("end", () => {
  const scenario = JSON.parse(input);
  const quotedPolicies: QuoteResult[] = [];
  const results = scenario.steps.map(
    (step: { op: string; items: Item[]; policy: number; incident: any }) => {
      if (step.op === "claim") {
        const policy = quotedPolicies[step.policy];
        const { payout, remainingCap } = claim(policy, step.incident);
        return { payout, remainingCap };
      }
      const result = quote(scenario.customer, step.items, { followUp: false });
      quotedPolicies[scenario.steps.indexOf(step)] = result;
      return { premium: result.premium };
    },
  );
  process.stdout.write(JSON.stringify({ results }));
});

